// 3. 웹 오디오 (Web Audio API) 효과음 설정
let audioCtx = null;

// 오디오 컨텍스트 활성화
function initAudio() {
    try {
        if (!audioCtx) {
            audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        }
        if (audioCtx.state === 'suspended') {
            audioCtx.resume();
        }
    } catch (e) {
        console.warn('AudioContext 초기화 오류:', e);
    }
}

// 벽돌 깨짐 비프음
function playBeepSound() {
    initAudio();
    if (!audioCtx) return;

    try {
        const osc = audioCtx.createOscillator();
        const gain = audioCtx.createGain();

        osc.connect(gain);
        gain.connect(audioCtx.destination);

        osc.type = 'triangle'; 
        osc.frequency.setValueAtTime(650, audioCtx.currentTime);

        gain.gain.setValueAtTime(0.15, audioCtx.currentTime); 
        gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + 0.12); 

        osc.start(audioCtx.currentTime);
        osc.stop(audioCtx.currentTime + 0.12);
    } catch (e) {
        console.warn('효과음 재생 실패:', e);
    }
}

// 아이템 획득 효과음
function playPowerUpSound() {
    initAudio();
    if (!audioCtx) return;

    try {
        const osc = audioCtx.createOscillator();
        const gain = audioCtx.createGain();

        osc.connect(gain);
        gain.connect(audioCtx.destination);

        osc.type = 'sine'; 
        
        const now = audioCtx.currentTime;
        osc.frequency.setValueAtTime(523.25, now);        
        osc.frequency.setValueAtTime(659.25, now + 0.08); 
        osc.frequency.setValueAtTime(783.99, now + 0.16); 

        gain.gain.setValueAtTime(0.12, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.3);

        osc.start(now);
        osc.stop(now + 0.3);
    } catch (e) {
        console.warn('파워업 사운드 재생 실패:', e);
    }
}

// 공 소환 효과음
function playSpawnSound() {
    initAudio();
    if (!audioCtx) return;

    try {
        const osc = audioCtx.createOscillator();
        const gain = audioCtx.createGain();

        osc.connect(gain);
        gain.connect(audioCtx.destination);

        osc.type = 'sine'; 
        
        const now = audioCtx.currentTime;
        osc.frequency.setValueAtTime(800, now);
        osc.frequency.exponentialRampToValueAtTime(1400, now + 0.08);

        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.08);

        osc.start(now);
        osc.stop(now + 0.08);
    } catch (e) {
        console.warn('공 소환 사운드 재생 실패:', e);
    }
}

// 스테이지 클리어 음악
function playStageClearSound() {
    initAudio();
    if (!audioCtx) return;

    try {
        const osc = audioCtx.createOscillator();
        const gain = audioCtx.createGain();

        osc.connect(gain);
        gain.connect(audioCtx.destination);

        osc.type = 'sine'; 
        
        const now = audioCtx.currentTime;
        osc.frequency.setValueAtTime(523.25, now);        
        osc.frequency.setValueAtTime(659.25, now + 0.12); 
        osc.frequency.setValueAtTime(783.99, now + 0.24); 
        osc.frequency.setValueAtTime(1046.50, now + 0.36); 

        gain.gain.setValueAtTime(0.15, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.6);

        osc.start(now);
        osc.stop(now + 0.6);
    } catch (e) {
        console.warn('스테이지 클리어 사운드 재생 실패:', e);
    }
}

// 타노스 목소리 발성 함수
function speakThanos() {
    try {
        if ('speechSynthesis' in window) {
            window.speechSynthesis.cancel();

            const utterance = new SpeechSynthesisUtterance("타노스 핑거 스냅");
            const voices = window.speechSynthesis.getVoices();
            
            const koVoice = voices.find(voice => voice.lang.includes('ko'));
            if (koVoice) {
                utterance.voice = koVoice;
            }

            utterance.pitch = 0.55; // 저음
            utterance.rate = 0.72;  // 느리게
            utterance.volume = 1.0; 

            window.speechSynthesis.speak(utterance);
        }
    } catch (e) {
        console.warn('음성 인식 오류:', e);
    }
}

// 4. 조작 키보드 상태 객체
const keys = {
    ArrowLeft: false,
    ArrowRight: false
};

// 5. game objects 설계

// [패들]
const paddle = {
    width: 100,
    targetWidth: 100,
    height: 12,
    x: (canvas.width - 100) / 2,
    y: 560,
    speed: 7,
    color: '#E8A33D',
    angle: 0,             // 현재 패들의 회전 각도 (라디안)
    isRotating: false     // 회전 애니메이션 실행 스위치
};

// 벽돌 기본 규격
const brickCols = 10;
const brickWidth = 68;
const brickHeight = 22;
const brickPadding = 4;
const brickOffsetTop = 60;
const brickOffsetLeft = 60;

// 행별 무지개 색상
const brickColors = [
    '#E05A4E', // 1행: 빨강
    '#E8A33D', // 2행: 주황
    '#FFD966', // 3행: 노랑
    '#2E9E5B', // 4행: 초록
    '#00AEEF', // 5행: 파랑
    '#9B51E0', // 6행: 보라
    '#E91E63', // 7행: 진분홍
    '#00E5FF'  // 8행: 네온 청록색 (헬 스테이지 세모 벽돌용!)
];

// 가변 행 개수 정의 변수
let brickRows = 5;
let bricks = [];

// 색상 보간
function interpolateColor(color1, color2, factor) {
    const r1 = parseInt(color1.substring(1, 3), 16);
    const g1 = parseInt(color1.substring(3, 5), 16);
    const b1 = parseInt(color1.substring(5, 7), 16);

    const r2 = parseInt(color2.substring(1, 3), 16);
    const g2 = parseInt(color2.substring(3, 5), 16);
    const b2 = parseInt(color2.substring(5, 7), 16);

    const r = Math.round(r1 + factor * (r2 - r1));
    const g = Math.round(g1 + factor * (g2 - g1));
    const b = Math.round(b1 + factor * (b2 - b1));

    return `rgb(${r}, ${g}, ${b})`;
}

// [회전 상자 충돌 해결사 (물리학 연산)]
// - 패들이나 벽돌이 특정 각도로 회전해 있을 때 공이 부딪히면 물리 법칙에 맞게 튕겨내는 고급 연산입니다.
function checkRotatedCollision(ballObj, rectX, rectY, rectW, rectH, angle) {
    // 1) 회전된 상자의 기하적 중심 좌표 계산
    const cx = rectX + rectW / 2;
    const cy = rectY + rectH / 2;
    
    // 2) 공의 좌표를 상자 중심 기준으로 평행 이동
    const dx = ballObj.x - cx;
    const dy = ballObj.y - cy;
    
    // 3) 상자의 역회전(-angle)만큼 공의 위치를 회전시켜, 축에 나란한 로컬 좌표계로 변환 (역회전 행렬 적용)
    const cos = Math.cos(-angle);
    const sin = Math.sin(-angle);
    const localX = dx * cos - dy * sin;
    const localY = dx * sin + dy * cos;
    
    // 4) 로컬 좌표계에서 상자 테두리 상의 가장 가까운 점(AABB 겹침검사) 찾기
    const px = Math.max(-rectW / 2, Math.min(rectW / 2, localX));
    const py = Math.max(-rectH / 2, Math.min(rectH / 2, localY));
    
    // 5) 로컬 상의 가장 가까운 점과 공의 거리 계산
    const distX = localX - px;
    const distY = localY - py;
    const distance = Math.sqrt(distX * distX + distY * distY);
    
    // 6) 충돌 발생 시 물리 반사 처리
    if (distance < ballObj.radius) {
        // 공의 비행 속도 벡터도 상자 기준 로컬 좌표계로 회전 변환
        const localVx = ballObj.dx * cos - ballObj.dy * sin;
        const localVy = ballObj.dx * sin + ballObj.dy * cos;
        
        // 부딪힌 표면의 로컬 법선 벡터(Normal Vector) 판정
        let localNx = 0;
        let localNy = 0;
        if (Math.abs(distX) > Math.abs(distY)) {
            localNx = distX > 0 ? 1 : -1;
        } else {
            localNy = distY > 0 ? 1 : -1;
        }
        
        // 내적(Dot Product)을 사용해 공이 상자를 파고들고 있는지 확인
        const dot = localVx * localNx + localVy * localNy;
        if (dot < 0) {
            // 탄성 충돌 반사 계산: v_new = v - 2 * (v . n) * n
            const newLocalVx = localVx - 2 * dot * localNx;
            const newLocalVy = localVy - 2 * dot * localNy;
            
            // 반사된 속도 벡터를 다시 글로벌 좌표계로 회전 변환
            const cosG = Math.cos(angle);
            const sinG = Math.sin(angle);
            ballObj.dx = newLocalVx * cosG - newLocalVy * sinG;
            ballObj.dy = newLocalVx * sinG + newLocalVy * cosG;
            
            // 상자 표면 밖으로 공 밀어내기 (겹침 버그 사전에 차단)
            const pushX = px + localNx * (ballObj.radius + 0.1);
            const pushY = py + localNy * (ballObj.radius + 0.1);
            ballObj.x = cx + pushX * cosG - pushY * sinG;
            ballObj.y = cy + pushX * sinG + pushY * cosG;
            
            return true; // 충돌 성공 보고
        }
    }
    return false; // 충돌 없음
}

// 벽돌판 빌드
function initBricks() {
    // 헬 스테이지는 벽돌을 7줄(70개)에 세모 벽돌 1줄을 추가하여 총 8줄(80개)의 벽을 구성합니다!
    if (isHellMode) {
        brickRows = 8;
    } else {
        brickRows = (stage === 1) ? 5 : 6;
    }
    
    const thanosR = Math.floor(Math.random() * brickRows);
    const thanosC = Math.floor(Math.random() * brickCols);
    
    bricks = [];
    for (let r = 0; r < brickRows; r++) {
        bricks[r] = [];
        for (let c = 0; c < brickCols; c++) {
            // 헬 스테이지의 경우 벽돌들을 무작위 회전각(최대 약 23도)으로 배치해 기하학적으로 혼란을 줍니다!
            const randomAngle = isHellMode ? (Math.random() - 0.5) * 0.8 : 0;
            // 헬 스테이지의 8번째 행(인덱스 7)은 전부 세모난 벽돌로 설정합니다.
            const isTriangleRow = (isHellMode && r === 7);
            bricks[r][c] = {
                x: c * (brickWidth + brickPadding) + brickOffsetLeft,
                y: r * (brickHeight + brickPadding) + brickOffsetTop,
                status: 1,
                color: brickColors[r] || '#00E5FF',
                hasThanosStone: (r === thanosR && c === thanosC),
                angle: randomAngle,
                shape: isTriangleRow ? 'TRIANGLE' : 'RECTANGLE'
            };
        }
    }
}

// 공 리셋
function resetBall() {
    balls = [];
    let speedMultiplier = 1.0;
    if (isHellMode) {
        speedMultiplier = 2.0; // 헬 스테이지는 공의 속도가 2배 빨라집니다!
    } else {
        speedMultiplier = (stage === 1) ? 1.0 : 1.35;
    }
    const baseSpeed = 4 * speedMultiplier;
    
    balls.push({
        x: paddle.x + paddle.width / 2,
        y: paddle.y - 8,
        radius: 8,
        dx: baseSpeed,
        dy: -baseSpeed,
        color: '#ffffff'
    });
}

// 공 소환
function spawnExtraBall() {
    const source = balls[0] || { x: paddle.x + paddle.width / 2, y: paddle.y - 8, dx: 4, dy: -4 };
    
    balls.push({
        x: source.x,
        y: source.y,
        radius: 8,
        dx: -source.dx + (Math.random() - 0.5) * 2,
        dy: source.dy,
        color: '#ffffff'
    });
    playSpawnSound();
    gameFooter.textContent = `다중 공 활성화! 현재 공 개수: ${balls.length}개`;
}

// 최고 기록 저장
function updateHighScore() {
    if (score > highScore) {
        highScore = score;
        localStorage.setItem('brick_breaker_high_score', highScore);
    }
}

// 타노스 핑거 스냅 먼지 입자 초기화
function triggerThanosSnap(bricksToDestroy) {
    snapStartTime = Date.now();
    snapBricks = bricksToDestroy;
    snapParticles = [];

    bricksToDestroy.forEach(b => {
        b.isDissolving = true; 

        for (let i = 0; i < 20; i++) {
            snapParticles.push({
                x: b.x + Math.random() * brickWidth,
                y: b.y + Math.random() * brickHeight,
                vx: (Math.random() - 0.5) * 1.8,  
                vy: -Math.random() * 2.5 - 0.5,   
                life: 1.0,                        
                decay: 0.008 + Math.random() * 0.015, 
                color: b.color
            });
        }
    });
}

// 6. 게임 구동 및 제어 함수

function startGame() {
    initAudio();
    isHellMode = false; // 일반 시작 시 헬 모드는 비활성화됩니다.
    normalStageButton.classList.add('active');
    hellStageButton.classList.remove('active');
    showHellTooltip = false;
    paddle.angle = 0;
    paddle.isRotating = false;
    microBrick = null;  // 초미니 보너스 벽돌 리셋

    gameState = 'PLAYING';
    isVictory = false;
    startButton.classList.add('hidden');
    gameFooter.textContent = '방향키(←, →)로 패들 제어 | F키를 누르면 공이 추가됩니다!';
    
    score = 0;
    lives = 3;
    stage = 1;
    items = [];
    paddle.targetWidth = 100;
    paddle.width = 100;
    powerUpTimeEnd = 0;
    
    paddle.x = (canvas.width - paddle.width) / 2;
    initBricks();
    resetBall();
    launchTime = Date.now() + 99999999; // 스페이스바 누르기 전까지 발사 대기
    gameFooter.textContent = '방향키 또는 마우스/터치로 패들 제어 | 스페이스바/터치로 발사!';
}

// 키보드 리스너
window.addEventListener('keydown', (e) => {
    initAudio();
    
    if (e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
        keys[e.key] = true;
        if (gameState === 'PLAYING') {
            e.preventDefault();
        }
    }
    if (e.key === ' ' || e.code === 'Space') {
        if (gameState === 'GAMEOVER' || gameState === 'START') {
            e.preventDefault();
            if (isHellMode) {
                startHellStage();
            } else {
                startGame();
            }
        } else if (gameState === 'PLAYING' && (Date.now() < launchTime)) {
            // [공 발사] 스페이스바 입력 시 대기 상태를 풀고 발사
            e.preventDefault();
            
            if (isHellMode) {
                // 헬 스테이지: 패들 각도에 맞춰 발사 속도 동조
                const speedMultiplier = 2.0;
                const baseSpeed = 4 * speedMultiplier;
                balls.forEach(ballObj => {
                    ballObj.dx = baseSpeed * Math.sin(paddle.angle);
                    ballObj.dy = -baseSpeed * Math.cos(paddle.angle);
                });
                showHellTooltip = false;
                gameFooter.textContent = `발사 완료! (패들 지속 회전중)`;
            } else {
                gameFooter.textContent = `발사 완료! | F키를 누르면 공 추가`;
            }
            
            launchTime = Date.now(); // 대기를 깨트리고 즉시 발사!
            playPowerUpSound();
        }
    }
    if (e.key === 'f' || e.key === 'F' || e.code === 'KeyF') {
        if (gameState === 'PLAYING') {
            e.preventDefault();
            spawnExtraBall();
        }
    }
    // [테스트용 단축키] T 키를 누르면 타노스 보라색 스톤이 패들 머리 위에서 즉시 낙하합니다.
    if (e.key === 't' || e.key === 'T' || e.code === 'KeyT') {
        if (gameState === 'PLAYING') {
            e.preventDefault();
            items.push({
                x: paddle.x + paddle.width / 2,
                y: 100,
                width: 16,
                height: 20,
                dy: 2.0,            
                color: '#9B51E0',   
                type: 'THANOS'      
            });
            gameFooter.textContent = '개발자 테스트: 타노스 스톤 즉시 낙하!';
        }
    }
});

window.addEventListener('keyup', (e) => {
    if (e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
        keys[e.key] = false;
    }
});

function handleScreenTap() {
    initAudio();
    if (gameState === 'START' || gameState === 'GAMEOVER') {
        if (isHellMode) {
            startHellStage();
        } else {
            startGame();
        }
    } else if (gameState === 'PLAYING' && (Date.now() < launchTime)) {
        // [공 발사] 터치(클릭) 시 대기 상태를 풀고 발사
        
        if (isHellMode) {
            const speedMultiplier = 2.0;
            const baseSpeed = 4 * speedMultiplier;
            balls.forEach(ballObj => {
                ballObj.dx = baseSpeed * Math.sin(paddle.angle);
                ballObj.dy = -baseSpeed * Math.cos(paddle.angle);
            });
            showHellTooltip = false;
            gameFooter.textContent = `발사 완료! (패들 지속 회전중)`;
        } else {
            gameFooter.textContent = `발사 완료! | F키를 누르면 공 추가`;
        }
        
        launchTime = Date.now();
        playPowerUpSound();
    }
}

canvas.addEventListener('click', handleScreenTap);
canvas.addEventListener('touchend', handleScreenTap);

// 터치 및 마우스 이벤트 리스너 추가 (모바일 패들 이동 지원)
function handlePointerMove(e) {
    if (gameState === 'PLAYING') {
        const rect = canvas.getBoundingClientRect();
        const scaleX = canvas.width / rect.width;
        let clientX = e.touches ? e.touches[0].clientX : e.clientX;
        let pointerX = (clientX - rect.left) * scaleX;
        
        // 패들의 중심이 포인터한 곳으로 오도록 설정
        paddle.x = pointerX - paddle.width / 2;
        
        // 캔버스 밖으로 나가지 않도록 경계 보정
        if (paddle.x < 0) paddle.x = 0;
        if (paddle.x + paddle.width > canvas.width) paddle.x = canvas.width - paddle.width;
        
        if (e.touches) {
            e.preventDefault(); // 모바일 스크롤 방지
        }
    }
}

canvas.addEventListener('touchstart', handlePointerMove, { passive: false });
canvas.addEventListener('touchmove', handlePointerMove, { passive: false });
canvas.addEventListener('mousemove', handlePointerMove);

startButton.addEventListener('click', () => {
    if (isHellMode) {
        startHellStage();
    } else {
        startGame();
    }
});

normalStageButton.addEventListener('click', () => {
    startGame();
});

// 헬 스테이지 전용 시작 함수
function startHellStage() {
    initAudio();
    isHellMode = true; // 헬 스테이지 스위치 켜기
    hellStageButton.classList.add('active');
    normalStageButton.classList.remove('active');
    showHellTooltip = true; // 가이드 말풍선 활성화

    gameState = 'PLAYING';
    isVictory = false;
    startButton.classList.add('hidden');
    gameFooter.textContent = '★ 헬 스테이지 활성화! 스페이스(또는 터치)를 눌러 공을 발사하세요! (패들 자동 회전) ★';
    
    score = 0;
    lives = 1;  // 목숨 단 1개로 제한!
    stage = 1;
    items = [];
    
    // 패들 크기는 축소하지 않고 원래대로(100px) 유지합니다!
    paddle.targetWidth = 100;
    paddle.width = 100;
    paddle.angle = 0;
    paddle.isRotating = true; // 회전 시작!
    powerUpTimeEnd = 0;
    
    paddle.x = (canvas.width - paddle.width) / 2;
    initBricks(); // 7줄 벽돌 초기화 (각도 랜덤)
    resetBall();  // 2배 속도 공 로드
    
    // 초미니 깜빡이 보너스 벽돌 배치 (4px 크기의 극초소형 깜빡이 벽돌)
    microBrick = {
        x: canvas.width / 2 - 2, // 캔버스 정중앙 X 좌표 (너비가 4px이므로 중앙 정렬을 위해 2 뺌)
        y: 280,                 // 벽돌 장벽 아래 넉넉한 허공 공간 Y 좌표
        width: 4,               // 4px 극초소형 크기 (AABB 판정)
        height: 4,
        status: 1,
        color: '#FF1493',       // 네온 핫핑크 색상
        showTooltip: true       // 설명 말풍선 표시용 플래그
    };
    
    // 무제한 발사 대기
    launchTime = Date.now() + 99999999;
}

// 헬 스테이지 버튼 클릭 이벤트 리스너 연결
hellStageButton.addEventListener('click', () => {
    startHellStage();
});

// 공과 벽돌의 충돌 판정
function checkBrickCollisions(ballObj) {
    // 헬 스테이지 초미니 깜빡이 벽돌 충돌 처리
    if (isHellMode && microBrick && microBrick.status === 1) {
        const mb = microBrick;
        if (ballObj.x + ballObj.radius > mb.x && 
            ballObj.x - ballObj.radius < mb.x + mb.width && 
            ballObj.y + ballObj.radius > mb.y && 
            ballObj.y - ballObj.radius < mb.y + mb.height) {
            
            mb.status = 0;
            score += 100; // 보너스 100점!
            updateHighScore();
            playStageClearSound(); // 축하 멜로디 연주
            gameFooter.textContent = '★ 대단합니다! 1px 초미니 깜빡이 벽돌을 격파하셨습니다! (+100점) ★';
            ballObj.dy = -ballObj.dy; // 공 반사
            mb.showTooltip = false; // 설명 말풍선 숨김
        }
    }

    let activeBricks = 0;
    for (let r = 0; r < brickRows; r++) {
        for (let c = 0; c < brickCols; c++) {
            const b = bricks[r][c];
            if (b.status === 1) {
                activeBricks++;
                
                if (checkRotatedCollision(ballObj, b.x, b.y, brickWidth, brickHeight, b.angle || 0)) {
                    b.status = 0;
                    score += 10;
                    updateHighScore(); 
                    playBeepSound(); 
                    
                    // 아이템 드롭 전직
                    if (b.hasThanosStone) {
                        items.push({
                            x: b.x + brickWidth / 2,
                            y: b.y + brickHeight / 2,
                            width: 16,
                            height: 20,
                            dy: 2.0,            
                            color: '#9B51E0',   
                            type: 'THANOS'      
                        });
                    } else if (Math.random() < 0.25) {
                        items.push({
                            x: b.x + brickWidth / 2,
                            y: b.y + brickHeight / 2,
                            width: 14,
                            height: 18,
                            dy: 2.5,
                            color: '#00E5FF',
                            type: 'EXPAND'
                        });
                    }
                    return;
                }
            }
        }
    }

    if (activeBricks === 0 && gameState === 'PLAYING') {
        updateHighScore(); 
        if (isHellMode) {
            // 헬 모드는 1개 스테이지를 모두 부순 순간 최종 승리합니다!
            gameState = 'GAMEOVER';
            isVictory = true;
            gameFooter.textContent = '대단합니다! 당신은 악마의 헬 스테이지를 정복하셨습니다! Spacebar를 눌러 재시작하세요.';
        } else if (stage === 1) {
            gameState = 'STAGE_CLEAR';
            transitionEndTime = Date.now() + 2500; 
            playStageClearSound();
            gameFooter.textContent = 'Stage 1 클리어! 곧이어 더 빠르고 벽돌이 많아진 Stage 2가 시작됩니다.';
        } else {
            gameState = 'GAMEOVER';
            isVictory = true;
            gameFooter.textContent = 'Congratulations! 모든 스테이지를 클리어하셨습니다! Spacebar를 눌러 재시작하세요.';
        }
    }
}
// HUD 그리기
function drawHUD() {
    ctx.save();
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 18px "Malgun Gothic", "맑은 고딕", sans-serif';
    ctx.shadowColor = 'rgba(255, 255, 255, 0.3)';
    ctx.shadowBlur = 4;

    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';
    ctx.fillText(`점수: ${score}`, 10, 25);

    ctx.textAlign = 'center';
    const stageStr = isHellMode ? 'HELL' : stage;
    ctx.fillText(`스테이지: ${stageStr}`, canvas.width / 2, 25);

    ctx.textAlign = 'right';
    ctx.fillText(`생명: ${lives}`, canvas.width - 10, 25);
    ctx.restore();
}

// 벽돌 그리기
function drawBricks() {
    for (let r = 0; r < brickRows; r++) {
        for (let c = 0; c < brickCols; c++) {
            const b = bricks[r][c];
            if (b.status === 1) {
                ctx.save();
                
                if (b.isDissolving) {
                    const elapsed = Date.now() - snapStartTime;
                    const alpha = Math.max(0, 1 - (elapsed / 3000)); 
                    ctx.globalAlpha = alpha;
                }

                ctx.fillStyle = b.color;
                ctx.shadowColor = b.color;
                ctx.shadowBlur = 8;
                
                // 헬 스테이지에서는 벽돌들의 개별 회전각(b.angle)을 캔버스 그리기 컨텍스트에 반영합니다.
                const angle = (isHellMode && b.angle) ? b.angle : 0;
                const cx = b.x + brickWidth / 2;
                const cy = b.y + brickHeight / 2;
                
                ctx.translate(cx, cy); // 벽돌 중심으로 좌표 평행이동
                if (angle !== 0) {
                    ctx.rotate(angle);  // 회전
                }
                
                ctx.beginPath();
                if (b.shape === 'TRIANGLE') {
                    // 세모 벽돌 그리기 (뾰족한 부분 꼭짓점이 아래를 향하는 모양)
                    ctx.moveTo(-brickWidth / 2, -brickHeight / 2); // 좌상단
                    ctx.lineTo(brickWidth / 2, -brickHeight / 2);  // 우상단
                    ctx.lineTo(0, brickHeight / 2);               // 하단 꼭짓점
                    ctx.closePath();
                } else {
                    // 사각형 벽돌 그리기
                    if (ctx.roundRect) {
                        ctx.roundRect(-brickWidth / 2, -brickHeight / 2, brickWidth, brickHeight, 4);
                    } else {
                        ctx.rect(-brickWidth / 2, -brickHeight / 2, brickWidth, brickHeight);
                    }
                }
                ctx.fill();
                
                ctx.shadowBlur = 0;
                ctx.strokeStyle = '#020108'; 
                ctx.lineWidth = 1;
                ctx.stroke();
                ctx.restore();
            }
        }
    }
    
    // [헬 스테이지 초미니 깜빡이 벽돌 그리기]
    if (isHellMode && microBrick && microBrick.status === 1) {
        const mb = microBrick;
        // 150ms 주기로 빠르게 깜빡입니다.
        const isVisible = (Math.floor(Date.now() / 150) % 2 === 0);
        if (isVisible) {
            ctx.save();
            ctx.fillStyle = mb.color;
            ctx.shadowColor = mb.color;
            ctx.shadowBlur = 12;
            ctx.fillRect(mb.x, mb.y, mb.width, mb.height);
            ctx.restore();
        }
    }
}

// 아이템 캡슐 및 다이아몬드 타노스 돌 렌더링
function drawItems() {
    for (let i = 0; i < items.length; i++) {
        const item = items[i];
        
        if (item.type === 'THANOS') {
            ctx.save();
            ctx.fillStyle = item.color;
            ctx.shadowColor = item.color;
            ctx.shadowBlur = 18; 
            
            ctx.beginPath();
            ctx.moveTo(item.x, item.y - item.height/2);
            ctx.lineTo(item.x + item.width/2, item.y);
            ctx.lineTo(item.x, item.y + item.height/2);
            ctx.lineTo(item.x - item.width/2, item.y);
            ctx.closePath();
            ctx.fill();
            
            ctx.fillStyle = '#ffffff';
            ctx.beginPath();
            ctx.moveTo(item.x, item.y - item.height/4);
            ctx.lineTo(item.x + item.width/4, item.y);
            ctx.lineTo(item.x, item.y + item.height/4);
            ctx.lineTo(item.x - item.width/4, item.y);
            ctx.closePath();
            ctx.fill();
            ctx.restore();
        } else {
            ctx.save();
            ctx.fillStyle = item.color;
            ctx.shadowColor = item.color;
            ctx.shadowBlur = 12;
            
            ctx.beginPath();
            if (ctx.roundRect) {
                ctx.roundRect(item.x - item.width/2, item.y - item.height/2, item.width, item.height, 5);
            } else {
                ctx.rect(item.x - item.width/2, item.y - item.height/2, item.width, item.height);
            }
            ctx.fill();
            
            ctx.fillStyle = '#ffffff';
            ctx.beginPath();
            if (ctx.roundRect) {
                ctx.roundRect(item.x - item.width/4, item.y - item.height/4, item.width/2, item.height/2, 2);
            } else {
                ctx.rect(item.x - item.width/4, item.y - item.height/4, item.width/2, item.height/2);
            }
            ctx.fill();
            ctx.restore();
        }
    }
}

// 8. 메인 애니메이션 루프
function animate() {
    ctx.fillStyle = '#000000';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 격자 배경
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.02)';
    ctx.lineWidth = 1;
    const gridSize = 40;
    for (let x = 0; x < canvas.width; x += gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, canvas.height);
        ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(canvas.width, y);
        ctx.stroke();
    }

    // --- [START] 대기 화면 ---
    if (gameState === 'START') {
        resetBall();

        pulse += 0.04;
        const glowRadius = 15 + Math.sin(pulse) * 8;

        ctx.save();
        ctx.shadowColor = 'rgba(255, 255, 255, 0.9)';
        ctx.shadowBlur = glowRadius;
        ctx.fillStyle = '#ffffff';
        ctx.font = '900 64px "Orbitron", sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        if ('letterSpacing' in ctx) {
            ctx.letterSpacing = '6px';
        }
        ctx.fillText('TAE SUB GAMES', canvas.width / 2, canvas.height * 0.38);
        ctx.restore();

        ctx.save();
        const pulseAlpha = 0.5 + Math.sin(Date.now() / 250) * 0.4;
        ctx.fillStyle = `rgba(255, 255, 255, ${pulseAlpha})`;
        ctx.font = 'bold 20px "Orbitron", sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        if ('letterSpacing' in ctx) {
            ctx.letterSpacing = '2px';
        }
        ctx.shadowColor = 'rgba(255, 255, 255, 0.3)';
        ctx.shadowBlur = 6;
        ctx.fillText('PRESS SPACE TO START', canvas.width / 2, canvas.height * 0.60);
        ctx.restore();

        ctx.save();
        ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
        ctx.font = 'bold 18px "Malgun Gothic", "맑은 고딕", sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(`최고 기록: ${highScore}점`, canvas.width / 2, canvas.height * 0.68);
        ctx.restore();

        drawBricks();

        ctx.save();
        ctx.fillStyle = paddle.color;
        ctx.shadowColor = paddle.color;
        ctx.shadowBlur = 15;
        ctx.beginPath();
        if (ctx.roundRect) {
            ctx.roundRect(paddle.x, paddle.y, paddle.width, paddle.height, 4);
        } else {
            ctx.rect(paddle.x, paddle.y, paddle.width, paddle.height);
        }
        ctx.fill();
        ctx.restore();

        if (balls.length > 0) {
            ctx.save();
            ctx.fillStyle = balls[0].color;
            ctx.shadowColor = balls[0].color;
            ctx.shadowBlur = 8;
            ctx.beginPath();
            ctx.arc(balls[0].x, balls[0].y, balls[0].radius, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }

        drawHUD();

    // --- [PLAYING] 실제 플레이 화면 ---
    } else if (gameState === 'PLAYING') {
        
        // 1) 위치 업데이트 (Update State)

        if (keys.ArrowLeft) {
            paddle.x -= paddle.speed;
        }
        if (keys.ArrowRight) {
            paddle.x += paddle.speed;
        }

        const oldWidth = paddle.width;
        paddle.width += (paddle.targetWidth - paddle.width) * 0.1;
        paddle.x -= (paddle.width - oldWidth) / 2;

        if (paddle.x < 0) {
            paddle.x = 0;
        }
        if (paddle.x > canvas.width - paddle.width) {
            paddle.x = canvas.width - paddle.width;
        }

        // 헬 스테이지 패들 자동 회전 연산
        if (isHellMode && paddle.isRotating) {
            paddle.angle += 0.1; // 프레임당 약 5.7도씩 빠르게 회전 (속도 2.5배 증가)
            if (paddle.angle > Math.PI * 2) {
                paddle.angle -= Math.PI * 2;
            }
        }

        const now = Date.now();
        const isDelayed = now < launchTime;

        // 파워업 만료 체크
        if (paddle.targetWidth === 200 && now > powerUpTimeEnd) {
            paddle.targetWidth = 100;
            gameFooter.textContent = '파워업 만료! 패들이 원래 크기로 복귀했습니다.';
        }

        // 아이템 캡슐 처리
        for (let i = items.length - 1; i >= 0; i--) {
            const item = items[i];
            item.y += item.dy;

            if (item.y + item.height/2 >= paddle.y && 
                item.y - item.height/2 <= paddle.y + paddle.height &&
                item.x >= paddle.x && 
                item.x <= paddle.x + paddle.width) {
                
                if (item.type === 'THANOS') {
                    // ★ 타노스 핑거 스냅 발동 ★
                    gameState = 'THANOS_SNAP'; 
                    speakThanos(); 

                    let activeBricksList = [];
                    for (let r = 0; r < brickRows; r++) {
                        for (let c = 0; c < brickCols; c++) {
                            if (bricks[r][c].status === 1) {
                                activeBricksList.push(bricks[r][c]);
                            }
                        }
                    }

                    const halfCount = Math.floor(activeBricksList.length / 2);
                    activeBricksList.sort(() => Math.random() - 0.5); 
                    const bricksToDestroy = activeBricksList.slice(0, halfCount); 

                    triggerThanosSnap(bricksToDestroy); 
                } else {
                    paddle.targetWidth = 200;
                    powerUpTimeEnd = Date.now() + 8000;
                    playPowerUpSound(); 
                    gameFooter.textContent = '★ 파워업! 패들 크기 2배 확장! (8초 유지) ★';
                }
                
                items.splice(i, 1);
                continue;
            }

            if (item.y - item.height/2 > canvas.height) {
                items.splice(i, 1);
            }
        }

        // 다중 공 물리 처리 루프
        for (let i = balls.length - 1; i >= 0; i--) {
            const ballObj = balls[i];

            if (isDelayed) {
                if (isHellMode) {
                    // 헬 스테이지에서는 발사 전에 공이 패들의 회전에 동조되어 원 궤도로 매끄럽게 회전합니다.
                    const cx = paddle.x + paddle.width / 2;
                    const cy = paddle.y + paddle.height / 2;
                    const offset = paddle.height / 2 + ballObj.radius;
                    ballObj.x = cx + offset * Math.sin(paddle.angle);
                    ballObj.y = cy - offset * Math.cos(paddle.angle);
                } else {
                    ballObj.x = paddle.x + paddle.width / 2;
                    ballObj.y = paddle.y - ballObj.radius;
                }
            } else {
                ballObj.x += ballObj.dx;
                ballObj.y += ballObj.dy;

                if (ballObj.x - ballObj.radius < 0) {
                    ballObj.x = ballObj.radius;
                    ballObj.dx = -ballObj.dx;
                } else if (ballObj.x + ballObj.radius > canvas.width) {
                    ballObj.x = canvas.width - ballObj.radius;
                    ballObj.dx = -ballObj.dx;
                }

                if (ballObj.y - ballObj.radius < 0) {
                    ballObj.y = ballObj.radius;
                    ballObj.dy = -ballObj.dy;
                }

                checkBrickCollisions(ballObj);

                if (isHellMode) {
                    // [헬 스테이지 회전 패들 충돌 판정]
                    // 각도가 틀어진 패들과 부딪혔을 때 물리 공식에 의한 올바른 반사 연산을 수행합니다.
                    if (checkRotatedCollision(ballObj, paddle.x, paddle.y, paddle.width, paddle.height, paddle.angle)) {
                        playBeepSound();
                    }
                } else {
                    // [일반 스테이지 축정렬 패들 충돌 판정]
                    if (ballObj.dy > 0 && 
                        ballObj.y + ballObj.radius >= paddle.y && 
                        ballObj.y - ballObj.radius <= paddle.y + paddle.height &&
                        ballObj.x >= paddle.x && 
                        ballObj.x <= paddle.x + paddle.width) {
                        
                        ballObj.dy = -Math.abs(ballObj.dy);
                        ballObj.y = paddle.y - ballObj.radius;

                        const hitPoint = (ballObj.x - (paddle.x + paddle.width / 2)) / (paddle.width / 2);
                        ballObj.dx = hitPoint * 6;
                    }
                }

                if (ballObj.y - ballObj.radius > canvas.height) {
                    balls.splice(i, 1);
                    
                    if (balls.length === 0) {
                        lives--;
                        updateHighScore(); 
                        if (lives > 0) {
                            resetBall();
                            launchTime = Date.now() + 1000;
                            gameFooter.textContent = `목숨 소실! 남은 목숨: ${lives}`;
                        } else {
                            gameState = 'GAMEOVER';
                            isVictory = false;
                            gameFooter.textContent = '게임 오버! Spacebar를 눌러서 처음부터 재시작하세요.';
                        }
                    } else {
                        gameFooter.textContent = `공 분실! 남은 공 개수: ${balls.length}개`;
                    }
                }
            }
        }

        // 2) 화면 렌더링
        ctx.save();
        ctx.fillStyle = 'rgba(255, 255, 255, 0.05)';
        ctx.font = '700 24px "Orbitron", sans-serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('GAME IN PROGRESS', canvas.width / 2, canvas.height / 2);
        ctx.restore();

        drawBricks();
        drawItems();

        // 패들 그리기
        ctx.save();
        const pct = (paddle.width - 100) / 100;
        const currentPaddleColor = interpolateColor('#E8A33D', '#00E5FF', pct);
        ctx.fillStyle = currentPaddleColor;
        ctx.shadowColor = currentPaddleColor;
        ctx.shadowBlur = 15;
        
        // 헬 스테이지에서는 패들의 현재 회전각을 드로잉에 그대로 적용합니다.
        if (isHellMode && paddle.angle !== 0) {
            const cx = paddle.x + paddle.width / 2;
            const cy = paddle.y + paddle.height / 2;
            ctx.translate(cx, cy);
            ctx.rotate(paddle.angle);
            ctx.beginPath();
            if (ctx.roundRect) {
                ctx.roundRect(-paddle.width / 2, -paddle.height / 2, paddle.width, paddle.height, 4);
            } else {
                ctx.rect(-paddle.width / 2, -paddle.height / 2, paddle.width, paddle.height);
            }
            ctx.fill();
        } else {
            ctx.beginPath();
            if (ctx.roundRect) {
                ctx.roundRect(paddle.x, paddle.y, paddle.width, paddle.height, 4);
            } else {
                ctx.rect(paddle.x, paddle.y, paddle.width, paddle.height);
            }
            ctx.fill();
        }
        ctx.restore();
        
        // 다중 공 그리기
        for (let i = 0; i < balls.length; i++) {
            const ballObj = balls[i];
            ctx.save();
            ctx.fillStyle = ballObj.color;
            ctx.shadowColor = ballObj.color;
            ctx.shadowBlur = 8;
            ctx.beginPath();
            ctx.arc(ballObj.x, ballObj.y, ballObj.radius, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }

        if (isDelayed) {
            ctx.save();
            ctx.fillStyle = '#ffffff';
            // 일반 1초 카운트다운은 헬 스테이지에서는 수치가 너무 크므로 헬 모드 외에만 표시합니다.
            if (!isHellMode) {
                ctx.font = '900 48px "Orbitron", sans-serif';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.shadowColor = 'rgba(255, 255, 255, 0.8)';
                ctx.shadowBlur = 15;
                const remainingSec = Math.ceil((launchTime - now) / 1000);
                ctx.fillText(remainingSec, canvas.width / 2, canvas.height * 0.65);
            }
            ctx.restore();

            // [헬 스테이지 안내용 1회성 말풍선 그리기]
            if (isHellMode && showHellTooltip) {
                drawHellTooltip();
            }
            
            // [초미니 깜빡이 벽돌 설명용 1회성 말풍선 그리기]
            if (isHellMode && microBrick && microBrick.status === 1 && microBrick.showTooltip) {
                drawMicroBrickTooltip();
            }
        }

        drawHUD();

    // --- [THANOS_SNAP] 타노스 핑거 스냅 3초간 시네마틱 연출 분기 ---
    } else if (gameState === 'THANOS_SNAP') {
        const now = Date.now();
        const elapsed = now - snapStartTime; 

        // 1) 먼지 입자 물리 업데이트 및 출력
        for (let i = snapParticles.length - 1; i >= 0; i--) {
            const p = snapParticles[i];
            p.x += p.vx;
            p.y += p.vy;
            p.life -= p.decay; 

            if (p.life <= 0) {
                snapParticles.splice(i, 1);
                continue;
            }

            ctx.save();
            ctx.fillStyle = p.color;
            ctx.shadowColor = p.color;
            ctx.shadowBlur = 6;
            ctx.globalAlpha = p.life; 
            ctx.beginPath();
            ctx.arc(p.x, p.y, 2 + Math.random() * 2, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }

        // 벽돌 렌더링
        drawBricks();

        // 멈춰있는 패들
        ctx.save();
        const pct = (paddle.width - 100) / 100;
        const currentPaddleColor = interpolateColor('#E8A33D', '#00E5FF', pct);
        ctx.fillStyle = currentPaddleColor;
        ctx.shadowColor = currentPaddleColor;
        ctx.shadowBlur = 15;
        ctx.beginPath();
        if (ctx.roundRect) {
            ctx.roundRect(paddle.x, paddle.y, paddle.width, paddle.height, 4);
        } else {
            ctx.rect(paddle.x, paddle.y, paddle.width, paddle.height);
        }
        ctx.fill();
        ctx.restore();

        // 멈춰있는 다중 공들
        for (let i = 0; i < balls.length; i++) {
            const ballObj = balls[i];
            ctx.save();
            ctx.fillStyle = ballObj.color;
            ctx.shadowColor = ballObj.color;
            ctx.shadowBlur = 8;
            ctx.beginPath();
            ctx.arc(ballObj.x, ballObj.y, ballObj.radius, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }

        // 고정 HUD
        drawHUD();

        // [타노스 핑거 스냅 이미지 중심 출력]
        if (thanosImg.complete && thanosImg.naturalWidth !== 0) {
            ctx.save();
            const imgAlpha = 0.82 + Math.sin(now / 120) * 0.08;
            ctx.globalAlpha = imgAlpha;
            
            const imgW = 320;
            const imgH = 240;
            const imgX = (canvas.width - imgW) / 2;
            const imgY = (canvas.height - imgH) / 2 - 40; 
            
            ctx.drawImage(thanosImg, imgX, imgY, imgW, imgH);
            
            ctx.strokeStyle = '#9B51E0';
            ctx.lineWidth = 4;
            ctx.shadowColor = '#9B51E0';
            ctx.shadowBlur = 22;
            ctx.strokeRect(imgX, imgY, imgW, imgH);
            ctx.restore();
        }

        // 시네마틱 보랏빛 광역 필터 효과
        ctx.save();
        const flashIntensity = 0.15 + Math.sin(now / 150) * 0.1;
        ctx.fillStyle = `rgba(155, 81, 224, ${flashIntensity})`; 
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.restore();

        // SNAP! 전광판 안내 텍스트
        ctx.save();
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        
        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 54px "Orbitron", sans-serif';
        ctx.shadowColor = '#9B51E0';
        ctx.shadowBlur = 20;
        ctx.fillText('SNAP!', canvas.width / 2, canvas.height / 2 + 130);

        ctx.fillStyle = '#888888';
        ctx.font = 'bold 16px "Malgun Gothic", "맑은 고딕", sans-serif';
        ctx.shadowBlur = 0;
        const remainingSec = Math.max(0, ((3000 - elapsed) / 1000)).toFixed(1);
        ctx.fillText(`우주 절멸 진행률: 50% | 남은 시간: ${remainingSec}초`, canvas.width / 2, canvas.height / 2 + 185);
        ctx.restore();

        // 3초(3000ms) 경과 확인
        if (elapsed >= 3000) {
            snapBricks.forEach(b => {
                b.status = 0;
                b.isDissolving = false;
            });
            score += snapBricks.length * 10; 
            updateHighScore();

            let activeBricks = 0;
            for (let r = 0; r < brickRows; r++) {
                for (let c = 0; c < brickCols; c++) {
                    if (bricks[r][c].status === 1) {
                        activeBricks++;
                    }
                }
            }

            if (activeBricks === 0) {
                if (stage === 1) {
                    gameState = 'STAGE_CLEAR';
                    transitionEndTime = Date.now() + 2500;
                    playStageClearSound();
                    gameFooter.textContent = 'Stage 1 클리어! 곧이어 더 빠르고 벽돌이 많아진 Stage 2가 시작됩니다.';
                } else {
                    gameState = 'GAMEOVER';
                    isVictory = true;
                    gameFooter.textContent = 'Congratulations! 모든 스테이지를 클리어하셨습니다! Spacebar를 눌러 재시작하세요.';
                }
            } else {
                gameState = 'PLAYING';
                launchTime = Date.now() + 500;
                gameFooter.textContent = '방향키(←, →)로 패들 제어 | F키를 누르면 공이 추가됩니다!';
            }
        }

    // --- [STAGE_CLEAR] 스테이지 전환 연출 화면 ---
    } else if (gameState === 'STAGE_CLEAR') {
        drawBricks();

        ctx.save();
        ctx.fillStyle = 'rgba(232, 163, 61, 0.4)'; 
        ctx.beginPath();
        if (ctx.roundRect) {
            ctx.roundRect(paddle.x, paddle.y, paddle.width, paddle.height, 4);
        } else {
            ctx.rect(paddle.x, paddle.y, paddle.width, paddle.height);
        }
        ctx.fill();
        ctx.restore();

        drawHUD();

        const now = Date.now();
        if (now >= transitionEndTime) {
            stage = 2;
            initBricks(); 
            resetBall();  
            gameState = 'PLAYING';
            launchTime = Date.now() + 1500; 
            gameFooter.textContent = 'Stage 2 시작! 공의 속도가 35% 상승합니다.';
        } else {
            ctx.save();
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            
            ctx.fillStyle = '#FFD966';
            ctx.font = 'bold 48px "Orbitron", sans-serif';
            ctx.shadowColor = 'rgba(255, 217, 102, 0.6)';
            ctx.shadowBlur = 15;
            ctx.fillText(`STAGE ${stage} CLEAR!`, canvas.width / 2, canvas.height / 2 - 60);

            ctx.fillStyle = '#ffffff';
            ctx.font = 'bold 24px "Malgun Gothic", "맑은 고딕", sans-serif';
            ctx.shadowBlur = 0;
            ctx.fillText('잠시 후 더 빠러진 STAGE 2가 시작됩니다.', canvas.width / 2, canvas.height / 2);

            ctx.fillStyle = '#888888';
            ctx.font = 'bold 16px "Malgun Gothic", "맑은 고딕", sans-serif';
            const remainingSec = Math.ceil((transitionEndTime - now) / 1000);
            ctx.fillText(`준비 시간: ${remainingSec}초...`, canvas.width / 2, canvas.height / 2 + 50);

            ctx.restore();
        }

    // --- [GAMEOVER] 게임 종료 화면 ---
    } else if (gameState === 'GAMEOVER') {
        drawBricks();

        ctx.save();
        ctx.fillStyle = 'rgba(232, 163, 61, 0.4)'; 
        ctx.beginPath();
        if (ctx.roundRect) {
            ctx.roundRect(paddle.x, paddle.y, paddle.width, paddle.height, 4);
        } else {
            ctx.rect(paddle.x, paddle.y, paddle.width, paddle.height);
        }
        ctx.fill();
        ctx.restore();

        for (let i = 0; i < balls.length; i++) {
            const ballObj = balls[i];
            ctx.save();
            ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
            ctx.beginPath();
            ctx.arc(ballObj.x, ballObj.y, ballObj.radius, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }

        drawHUD();

        ctx.save();
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';

        if (isVictory) {
            ctx.fillStyle = '#2E9E5B';
            ctx.font = 'bold 48px "Orbitron", sans-serif';
            ctx.shadowColor = 'rgba(46, 158, 91, 0.6)';
            ctx.shadowBlur = 15;
            ctx.fillText('You Win!', canvas.width / 2, canvas.height / 2 - 80);
        } else {
            ctx.fillStyle = '#E05A4E';
            ctx.font = 'bold 48px "Orbitron", sans-serif';
            ctx.shadowColor = 'rgba(224, 90, 78, 0.6)';
            ctx.shadowBlur = 15;
            ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2 - 80);
        }

        if (score > 0 && score === highScore) {
            ctx.save();
            const recordAlpha = 0.6 + Math.sin(Date.now() / 150) * 0.4;
            ctx.fillStyle = `rgba(255, 217, 102, ${recordAlpha})`;
            ctx.font = 'bold 18px "Orbitron", sans-serif';
            ctx.shadowColor = 'rgba(255, 217, 102, 0.8)';
            ctx.shadowBlur = 8;
            ctx.fillText('★ NEW RECORD ★', canvas.width / 2, canvas.height / 2 - 30);
            ctx.restore();
        }

        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 24px "Malgun Gothic", "맑은 고딕", sans-serif';
        ctx.shadowBlur = 0; 
        ctx.fillText(`최종 점수 : ${score}점`, canvas.width / 2, canvas.height / 2 + 10);

        ctx.fillStyle = '#FFD966';
        ctx.font = 'bold 20px "Malgun Gothic", "맑은 고딕", sans-serif';
        ctx.fillText(`최고 기록 : ${highScore}점`, canvas.width / 2, canvas.height / 2 + 45);

        ctx.fillStyle = '#888888';
        ctx.font = 'bold 16px "Malgun Gothic", "맑은 고딕", sans-serif';
        ctx.fillText('스페이스바로 재시작', canvas.width / 2, canvas.height / 2 + 85);

        ctx.restore();
    }

    requestAnimationFrame(animate);
}
function drawHellTooltip() {
    const cx = paddle.x + paddle.width / 2;
    const cy = paddle.y - 40;
    
    ctx.save();
    ctx.fillStyle = 'rgba(20, 0, 0, 0.85)';
    ctx.strokeStyle = '#FF3333';
    ctx.lineWidth = 2;
    ctx.shadowColor = '#FF0000';
    ctx.shadowBlur = 10;
    
    const bw = 380;
    const bh = 50;
    const bx = cx - bw / 2;
    const by = cy - bh / 2;
    
    ctx.beginPath();
    if (ctx.roundRect) {
        ctx.roundRect(bx, by, bw, bh, 5);
    } else {
        ctx.rect(bx, by, bw, bh);
    }
    ctx.fill();
    ctx.stroke();
    
    ctx.beginPath();
    ctx.moveTo(cx - 8, by + bh);
    ctx.lineTo(cx, by + bh + 8);
    ctx.lineTo(cx + 8, by + bh);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();
    
    ctx.shadowBlur = 0;
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 12px "Malgun Gothic", sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('SPACEBAR를 눌러 패들을 고정하고 공을 발사하세요!', cx, cy);
    ctx.restore();
}

function drawMicroBrickTooltip() {
    if (!microBrick) return;
    const cx = microBrick.x + microBrick.width / 2;
    const cy = microBrick.y - 30; 
    
    ctx.save();
    ctx.fillStyle = 'rgba(10, 5, 25, 0.9)'; 
    ctx.strokeStyle = '#FF1493';
    ctx.lineWidth = 2;
    ctx.shadowColor = '#FF1493';
    ctx.shadowBlur = 8;
    
    const bw = 260;
    const bh = 42;
    const bx = cx - bw / 2;
    const by = cy - bh / 2;
    
    ctx.beginPath();
    if (ctx.roundRect) {
        ctx.roundRect(bx, by, bw, bh, 5);
    } else {
        ctx.rect(bx, by, bw, bh);
    }
    ctx.fill();
    ctx.stroke();
    
    ctx.beginPath();
    ctx.moveTo(cx - 8, by + bh);
    ctx.lineTo(cx, by + bh + 8);
    ctx.lineTo(cx + 8, by + bh);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();
    
    ctx.shadowBlur = 0;
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 11px "Malgun Gothic", "맑은 고딕", sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('초미니 깜빡이 보너스 벽돌! 격파 시 +100점!', cx, cy);
    ctx.restore();
}

// 루프 시작
initBricks();
animate();
